1	//! Batch-mode output framing around an opaque theory payload.
2	//!
3	//! The theory pretty-print itself (`theory <name> … end`, including any
4	//! `WARNING:` block and the `Generated from:` comment) is treated as an opaque
5	//! payload slot. This module builds everything AROUND it: the maude preamble, the
6	//! per-theory progress lines, and the "summary of summaries" block.
7	
8	use crate::version::{maude_preamble, MaudeInfo};
9	
10	/// Width of the `=` rule that brackets the summary block (observed: 78).
11	const RULE_WIDTH: usize = 78;
12	
13	/// Per-theory progress phases, in the order printed for a fully closed theory.
14	#[derive(Debug, Clone, Copy)]
15	pub enum Phase {
16	    Loaded,
17	    Translated,
18	    DerivationChecksStarted,
19	    DerivationChecksEnded,
20	    Closed,
21	}
22	
23	impl Phase {
24	    fn text(self) -> &'static str {
25	        match self {
26	            Phase::Loaded => "Theory loaded",
27	            Phase::Translated => "Theory translated",
28	            Phase::DerivationChecksStarted => "Derivation checks started",
29	            Phase::DerivationChecksEnded => "Derivation checks ended",
30	            Phase::Closed => "Theory closed",
31	        }
32	    }
33	}
34	
35	/// The five progress phases a closed theory reports.
36	pub const CLOSED_PHASES: [Phase; 5] = [
37	    Phase::Loaded,
38	    Phase::Translated,
39	    Phase::DerivationChecksStarted,
40	    Phase::DerivationChecksEnded,
41	    Phase::Closed,
42	];
43	
44	/// One progress line: `[Theory <name>] <phase>\n`.
45	pub fn progress_line(theory: &str, phase: Phase) -> String {
46	    format!("[Theory {}] {}\n", theory, phase.text())
47	}
48	
49	fn progress_block(theory: &str, phases: &[Phase]) -> String {
50	    phases.iter().map(|p| progress_line(theory, *p)).collect()
51	}
52	
53	/// Whether a lemma quantifies over all traces or asserts an existing trace.
54	#[derive(Debug, Clone, Copy)]
55	pub enum TraceKind {
56	    AllTraces,
57	    ExistsTrace,
58	}
59	
60	impl TraceKind {
61	    fn text(self) -> &'static str {
62	        match self {
63	            TraceKind::AllTraces => "all-traces",
64	            TraceKind::ExistsTrace => "exists-trace",
65	        }
66	    }
67	}
68	
69	/// Per-lemma verdict.
70	#[derive(Debug, Clone, Copy)]
71	pub enum LemmaResult {
72	    Verified,
73	    Falsified,
74	    AnalysisIncomplete,
75	}
76	
77	impl LemmaResult {
78	    fn text(self) -> &'static str {
79	        match self {
80	            LemmaResult::Verified => "verified",
81	            LemmaResult::Falsified => "falsified",
82	            LemmaResult::AnalysisIncomplete => "analysis incomplete",
83	        }
84	    }
85	}
86	
87	/// One line of the summary body.
88	#[derive(Debug, Clone)]
89	pub enum SummaryEntry {
90	    Lemma { name: String, kind: TraceKind, result: LemmaResult, steps: u64 },
91	    /// `WARNING: <count> wellformedness check failed!` (note the singular "check").
92	    Warning { count: u64 },
93	}
94	
95	impl SummaryEntry {
96	    fn text(&self) -> String {
97	        match self {
98	            SummaryEntry::Lemma { name, kind, result, steps } => {
99	                format!("{} ({}): {} ({} steps)", name, kind.text(), result.text(), steps)
100	            }
101	            SummaryEntry::Warning { count } => {
102	                format!("WARNING: {} wellformedness check failed!", count)
103	            }
104	        }
105	    }
106	}
107	
108	/// The "summary of summaries" block, bracketed by `=` rules. `processing_time`
109	/// is rendered as seconds with two decimals (e.g. `0.39s`).
110	pub fn render_summary(analyzed_path: &str, processing_time: f64, entries: &[SummaryEntry]) -> String {
111	    let rule = "=".repeat(RULE_WIDTH);
112	    let mut out = String::new();
113	    out.push_str(&rule);
114	    out.push('\n');
115	    out.push_str("summary of summaries:\n");
116	    out.push('\n');
117	    out.push_str(&format!("analyzed: {}\n", analyzed_path));
118	    out.push('\n');
119	    out.push_str(&format!("  processing time: {:.2}s\n", processing_time));
120	    out.push_str("  \n"); // literal two-space separator line
121	    for e in entries {
122	        out.push_str(&format!("  {}\n", e.text()));
123	    }
124	    out.push('\n');
125	    out.push_str(&rule);
126	    out.push('\n');
127	    out
128	}
129	
130	/// The framing that precedes a closed theory's payload: the maude preamble
131	/// followed by the five progress lines.
132	pub fn frame_prefix(maude: &MaudeInfo, theory: &str) -> String {
133	    let mut out = maude_preamble(maude);
134	    out.push_str(&progress_block(theory, &CLOSED_PHASES));
135	    out
136	}
137	
138	/// Full framing for a processed (closed) theory: maude preamble, the five
139	/// progress lines, the opaque `payload`, then the summary block. `payload` must
140	/// be the pretty-printed theory ending with `end\n`.
141	pub fn frame_processed(
142	    maude: &MaudeInfo,
143	    theory: &str,
144	    payload: &str,
145	    analyzed_path: &str,
146	    processing_time: f64,
147	    entries: &[SummaryEntry],
148	) -> String {
149	    let mut out = frame_prefix(maude, theory);
150	    out.push_str(payload);
151	    out.push('\n'); // blank line between payload and summary rule
152	    out.push_str(&render_summary(analyzed_path, processing_time, entries));
153	    out
154	}
155	
156	/// Framing for `--parse-only`: a single `Theory loaded` progress line then the
157	/// opaque payload. No maude preamble and no summary block.
158	pub fn frame_parse_only(theory: &str, payload: &str) -> String {
159	    let mut out = String::new();
160	    out.push_str(&progress_line(theory, Phase::Loaded));
161	    out.push_str(payload);
162	    out
163	}
164

1	//! Help pages.
2	//!
3	//! The exact column widths, wrapping, and padding of each help page are
4	//! compatibility output taken verbatim from the binary; they are stored as
5	//! observed-output fixtures and emitted as opaque strings. `render_help` selects
6	//! the fixture for a mode.
7	
8	use crate::modes::Mode;
9	
10	const HELP_GLOBAL: &str = include_str!("../fixtures/help_global.txt");
11	const HELP_INTERACTIVE: &str = include_str!("../fixtures/help_interactive.txt");
12	const HELP_VARIANTS: &str = include_str!("../fixtures/help_variants.txt");
13	const HELP_TEST: &str = include_str!("../fixtures/help_test.txt");
14	
15	/// The help page for a mode, byte-for-byte as the binary prints it.
16	pub fn render_help(mode: Mode) -> &'static str {
17	    match mode {
18	        Mode::Batch => HELP_GLOBAL,
19	        Mode::Interactive => HELP_INTERACTIVE,
20	        Mode::Variants => HELP_VARIANTS,
21	        Mode::Test => HELP_TEST,
22	    }
23	}
24

1	//! Thin driver exercising the CLI text surface.
2	//!
3	//! Handles the pure-text paths (help, version, parse errors) byte-for-byte so
4	//! they can be verified against the black-box binary. `Run` has no prover engine
5	//! behind it here — real integration wires the parsed [`cli_clean::RunSpec`] into
6	//! the prover and uses [`cli_clean::framing`] to wrap its output.
7	
8	use std::process::exit;
9	
10	use cli_clean::version::{MaudeInfo, VersionInfo};
11	use cli_clean::{parse, render_version, Command};
12	
13	/// Version slots as observed from the reference build. Real integration injects
14	/// the actual build metadata of the hosting binary.
15	fn observed_version_info() -> VersionInfo {
16	    VersionInfo {
17	        maude: MaudeInfo::default(),
18	        tamarin_version: "1.13.0".to_string(),
19	        copyright_years: "2010-2023".to_string(),
20	        git_description: "0234f6a1abee25677c0accef62de0ac2883b0347 (with uncommited changes), branch: HEAD"
21	            .to_string(),
22	        compiled_at: "2026-07-16 18:33:16.036427196 UTC".to_string(),
23	    }
24	}
25	
26	fn main() {
27	    let argv: Vec<String> = std::env::args().skip(1).collect();
28	    match parse(&argv) {
29	        Ok(Command::Help(mode)) => {
30	            print!("{}", cli_clean::render_help(mode));
31	            exit(0);
32	        }
33	        Ok(Command::Version) => {
34	            print!("{}", render_version(&observed_version_info()));
35	            exit(0);
36	        }
37	        Ok(Command::Run(spec)) => {
38	            // Text-surface stub: no prover engine in this crate.
39	            eprintln!(
40	                "[cli-clean] parsed: mode={:?} positional={:?} flags={:?}",
41	                spec.mode, spec.positional, spec.options.flags
42	            );
43	            exit(0);
44	        }
45	        Err(e) => {
46	            eprint!("{}", e.text);
47	            exit(e.exit_code);
48	        }
49	    }
50	}
51

1	//! Byte-parity tests against captured oracle output.
2	//!
3	//! Fixtures in `tests/fixtures/` are raw captures of the black-box binary. The
4	//! framing and error-text tests compare assembled output against INDEPENDENT
5	//! full-run captures (not the source the renderers were built from), so they are
6	//! genuine byte-parity checks of the assembly logic.
7	
8	use cli_clean::errors::{app_error, open_file_error, OpenFileError};
9	use cli_clean::framing::{
10	    frame_parse_only, frame_prefix, render_summary, LemmaResult, SummaryEntry, TraceKind,
11	};
12	use cli_clean::version::{MaudeInfo, VersionInfo};
13	use cli_clean::{parse, render_help, render_version, Command, Mode};
14	
15	fn s(a: &str) -> String {
16	    a.to_string()
17	}
18	fn argv(items: &[&str]) -> Vec<String> {
19	    items.iter().map(|x| x.to_string()).collect()
20	}
21	
22	// ---- help ---------------------------------------------------------------------
23	
24	#[test]
25	fn help_pages_are_byte_exact() {
26	    assert_eq!(render_help(Mode::Batch), include_str!("fixtures/help_global.txt"));
27	    assert_eq!(render_help(Mode::Interactive), include_str!("fixtures/help_interactive.txt"));
28	    assert_eq!(render_help(Mode::Variants), include_str!("fixtures/help_variants.txt"));
29	    assert_eq!(render_help(Mode::Test), include_str!("fixtures/help_test.txt"));
30	}
31	
32	// ---- version ------------------------------------------------------------------
33	
34	fn observed_version() -> VersionInfo {
35	    VersionInfo {
36	        maude: MaudeInfo::default(),
37	        tamarin_version: s("1.13.0"),
38	        copyright_years: s("2010-2023"),
39	        git_description: s(
40	            "0234f6a1abee25677c0accef62de0ac2883b0347 (with uncommited changes), branch: HEAD",
41	        ),
42	        compiled_at: s("2026-07-16 18:33:16.036427196 UTC"),
43	    }
44	}
45	
46	#[test]
47	fn version_banner_is_byte_exact() {
48	    assert_eq!(render_version(&observed_version()), include_str!("fixtures/version.txt"));
49	    // -V produces the same output.
50	    assert_eq!(render_version(&observed_version()), include_str!("fixtures/short_version.txt"));
51	}
52	
53	// ---- parse errors -------------------------------------------------------------
54	
55	#[test]
56	fn unknown_long_flag() {
57	    let e = parse(&argv(&["--foobar"])).unwrap_err();
58	    assert_eq!(e.text, include_str!("fixtures/err_unknown_flag.txt"));
59	    assert_eq!(e.exit_code, 1);
60	}
61	
62	#[test]
63	fn unknown_short_flag() {
64	    let e = parse(&argv(&["-Z"])).unwrap_err();
65	    assert_eq!(e.text, include_str!("fixtures/err_unknown_short.txt"));
66	}
67	
68	#[test]
69	fn short_h_is_not_help() {
70	    // `-h` is unknown; help is `-?`/`--help`.
71	    let e = parse(&argv(&["-h"])).unwrap_err();
72	    assert_eq!(e.text, "Unknown flag: -h\n");
