//! Typed argument parsing with value validation.
//!
//! [`parse_args`] layers a typed surface over the structural [`crate::parse`]:
//! `parse_args(argv) -> Result<Parsed, ParseError>`. On success it yields either a
//! help/version request or a fully typed [`Args`] with integers parsed, enums
//! resolved, and documented defaults applied. On a value-validation failure it
//! yields a [`ParseError`] whose text and stream reproduce the reference binary's
//! output byte-for-byte (see `workspace/BEHAVIOR.md` §11).
//!
//! Only eight flags are value-validated (the rest accept any value). Validation
//! fires only for a *present* value (`=value`, `--oj=…`, or short-attached `-b5`);
//! a bare flag never fails. Repeated flags follow last-wins. When several flags
//! carry an invalid value, a fixed order — independent of command-line order —
//! decides which error surfaces:
//!
//! `stop-on-trace > bound > partial-evaluation > open-chains > saturation >
//! output-module > derivcheck-timeout > replication-bound`.

use crate::errors::{self, ParseError};
use crate::modes::Mode;
use crate::parse::{parse, Command, Options};

/// The `--stop-on-trace` method (matched case-insensitively).
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum StopOnTrace {
    Dfs,
    Bfs,
    SeqDfs,
    Sorry,
    None,
}

/// The `--partial-evaluation` mode (matched case-insensitively).
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum PartialEval {
    Summary,
    Verbose,
}

/// The `-m --output-module` target (matched case-sensitively).
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum OutputModule {
    SpthyTyped,
    Spthy,
    Msr,
    ProverifEquiv,
    Proverif,
    Deepsec,
}

/// Documented default for `--open-chains`.
pub const OPEN_CHAINS_DEFAULT: i64 = 10;
/// Documented default for `--saturation`.
pub const SATURATION_DEFAULT: i64 = 5;
/// Documented default for `--derivcheck-timeout`.
pub const DERIVCHECK_TIMEOUT_DEFAULT: i64 = 5;

/// A fully typed, validated command-line, with defaults applied.
///
/// Fields cover every flag the mode tables model. Flags irrelevant to the active
/// [`Mode`] simply hold their defaults. Bare-vs-valued is preserved only where it
/// is semantically load-bearing (the repeatable selectors); other single-valued
/// string flags collapse an absent or bare occurrence to `None`.
#[derive(Debug, Clone, PartialEq, Eq)]
pub struct Args {
    pub mode: Mode,
    /// FILES (batch/test) or the WORKDIR token(s) (interactive).
    pub positional: Vec<String>,

    // -- proving / lemma selection (repeatable; None element = bare occurrence) --
    pub prove: Vec<Option<String>>,
    pub lemma: Vec<Option<String>>,
    pub defines: Vec<Option<String>>,

    // -- value-validated flags --
    pub stop_on_trace: StopOnTrace,
    pub bound: Option<i64>,
    pub partial_evaluation: Option<PartialEval>,
    pub open_chains: i64,
    pub saturation: i64,
    pub output_module: Option<OutputModule>,
    pub derivcheck_timeout: i64,
    pub replication_bound: Option<i64>,

    // -- unvalidated value flags (raw last-occurrence value) --
    pub heuristic: Option<String>,
    pub oraclename: Option<String>,
    pub output: Option<String>,
    pub output_dir: Option<String>,
    pub output_json: Option<String>,
    pub output_dot: Option<String>,
    pub with_dot: Option<String>,
    pub with_json: Option<String>,
    pub with_maude: Option<String>,
    // interactive-only value flags (unvalidated by the reference)
    pub port: Option<String>,
    pub interface: Option<String>,
    pub image_format: Option<String>,

    // -- boolean flags --
    pub diff: bool,
    pub quit_on_warning: bool,
    pub auto_sources: bool,
    pub oracle_only: bool,
    pub quiet: bool,
    pub verbose: bool,
    pub no_reuse: bool,
    pub no_restrictions: bool,
    pub no_compress: bool,
    pub parse_only: bool,
    pub precompute_only: bool,
    pub debug: bool,
    pub no_logging: bool,

    // -- consumer-extension flags (not in the reference, not in help) --
    pub processors: Option<u64>,
    pub maude_processes: Option<u64>,
    pub data_dir: Option<String>,
}

/// The outcome of a typed parse: a help/version request, or a run with typed args.
#[derive(Debug, Clone, PartialEq, Eq)]
pub enum Parsed {
    Help(Mode),
    Version,
    Run(Args),
}

/// Typed parse of an argument vector (excluding argv[0]).
pub fn parse_args(argv: &[String]) -> Result<Parsed, ParseError> {
    match parse(argv)? {
        Command::Help(mode) => Ok(Parsed::Help(mode)),
        Command::Version => Ok(Parsed::Version),
        Command::Run(spec) => {
            let args = build_args(spec.mode, spec.positional, &spec.options)?;
            Ok(Parsed::Run(args))
        }
    }
}

/// Resolve typed fields, validating values in the fixed precedence order so the
/// first invalid flag in that order produces the surfaced error.
fn build_args(mode: Mode, positional: Vec<String>, o: &Options) -> Result<Args, ParseError> {
    // Precedence order: the earliest invalid flag here is the one that errors.
    let stop_on_trace = stop_on_trace_field(o)?;
    let bound = int_opt(o, "bound", "bound")?;
    let partial_evaluation = partial_eval_field(o)?;
    let open_chains = int_default(o, "open-chains", "OpenChainsLimit", OPEN_CHAINS_DEFAULT)?;
    let saturation = int_default(o, "saturation", "SaturationLimit", SATURATION_DEFAULT)?;
    let output_module = output_module_field(o)?;
    let derivcheck_timeout =
        int_default(o, "derivcheck-timeout", "derivcheck-timeout", DERIVCHECK_TIMEOUT_DEFAULT)?;
    let replication_bound = int_opt(o, "replication-bound", "replication-bound")?;

    // Consumer extensions (validated after all reference flags, so a reference
    // error always wins).
    let processors = positive_int_opt(o, "processors", "--processors")?;
    let maude_processes = positive_int_opt(o, "maude-processes", "--maude-processes")?;

    Ok(Args {
        mode,
        positional,
        prove: o.occurrences("prove"),
        lemma: o.occurrences("lemma"),
        defines: o.occurrences("defines"),
        stop_on_trace,
        bound,
        partial_evaluation,
        open_chains,
        saturation,
        output_module,
        derivcheck_timeout,
        replication_bound,
        heuristic: raw_opt(o, "heuristic"),
        oraclename: raw_opt(o, "oraclename"),
        output: raw_opt(o, "output"),
        output_dir: raw_opt(o, "Output"),
        output_json: raw_opt(o, "output-json"),
        output_dot: raw_opt(o, "output-dot"),
        with_dot: raw_opt(o, "with-dot"),
        with_json: raw_opt(o, "with-json"),
        with_maude: raw_opt(o, "with-maude"),
        port: raw_opt(o, "port"),
        interface: raw_opt(o, "interface"),
        image_format: raw_opt(o, "image-format"),
        diff: o.is_set("diff"),
        quit_on_warning: o.is_set("quit-on-warning"),
        auto_sources: o.is_set("auto-sources"),
        oracle_only: o.is_set("oracle-only"),
        quiet: o.is_set("quiet"),
        verbose: o.is_set("verbose"),
        no_reuse: o.is_set("no-reuse"),
        no_restrictions: o.is_set("no-restrictions"),
        no_compress: o.is_set("no-compress"),
        parse_only: o.is_set("parse-only"),
        precompute_only: o.is_set("precompute-only"),
        debug: o.is_set("debug"),
        no_logging: o.is_set("no-logging"),
        processors,
        maude_processes,
        data_dir: raw_opt(o, "data-dir"),
    })
}

/// Last-occurrence raw value (absent or bare → `None`).
fn raw_opt(o: &Options, long: &str) -> Option<String> {
    match o.last(long) {
        Some(Some(v)) => Some(v.to_string()),
        _ => None,
    }
}

/// Integer flag with no documented default: `None` when absent/bare, else the
/// parsed value or the flag's `invalid bound` error.
fn int_opt(o: &Options, long: &str, label: &str) -> Result<Option<i64>, ParseError> {
    match o.last(long) {
        Some(Some(v)) => match read_haskell_int(v) {
            Some(n) => Ok(Some(n)),
            None => Err(errors::invalid_bound(label)),
        },
        _ => Ok(None),
    }
}

/// Integer flag with a documented default applied for absent/bare occurrences.
fn int_default(o: &Options, long: &str, label: &str, default: i64) -> Result<i64, ParseError> {
    match o.last(long) {
        Some(Some(v)) => read_haskell_int(v).ok_or_else(|| errors::invalid_bound(label)),
        _ => Ok(default),
    }
}

/// `--stop-on-trace`: case-insensitive; default DFS; invalid value echoes the
/// lowercased input.
fn stop_on_trace_field(o: &Options) -> Result<StopOnTrace, ParseError> {
    match o.last("stop-on-trace") {
        Some(Some(v)) => {
            let lower = v.to_ascii_lowercase();
            match lower.as_str() {
                "dfs" => Ok(StopOnTrace::Dfs),
                "bfs" => Ok(StopOnTrace::Bfs),
                "seqdfs" => Ok(StopOnTrace::SeqDfs),
                "sorry" => Ok(StopOnTrace::Sorry),
                "none" => Ok(StopOnTrace::None),
                _ => Err(errors::unknown_stop_on_trace(&lower)),
            }
        }
        _ => Ok(StopOnTrace::Dfs),
    }
}

/// `--partial-evaluation`: case-insensitive; no default; no value echoed on error.
fn partial_eval_field(o: &Options) -> Result<Option<PartialEval>, ParseError> {
    match o.last("partial-evaluation") {
        Some(Some(v)) => match v.to_ascii_lowercase().as_str() {
            "summary" => Ok(Some(PartialEval::Summary)),
            "verbose" => Ok(Some(PartialEval::Verbose)),
            _ => Err(errors::partial_evaluation_unknown()),
        },
        _ => Ok(None),
    }
}

/// `-m --output-module`: case-SENSITIVE; no value echoed on error.
fn output_module_field(o: &Options) -> Result<Option<OutputModule>, ParseError> {
    match o.last("output-module") {
        Some(Some(v)) => match v {
            "spthytyped" => Ok(Some(OutputModule::SpthyTyped)),
            "spthy" => Ok(Some(OutputModule::Spthy)),
            "msr" => Ok(Some(OutputModule::Msr)),
            "proverifequiv" => Ok(Some(OutputModule::ProverifEquiv)),
            "proverif" => Ok(Some(OutputModule::Proverif)),
            "deepsec" => Ok(Some(OutputModule::Deepsec)),
            _ => Err(errors::output_mode_not_supported()),
        },
        _ => Ok(None),
    }
}

/// A consumer-extension positive-integer flag: `None` when absent/bare, else a
/// value ≥ 1 or an original (non-reference) rejection.
fn positive_int_opt(o: &Options, long: &str, flag: &str) -> Result<Option<u64>, ParseError> {
    match o.last(long) {
        Some(Some(v)) => match v.trim().parse::<u64>() {
            Ok(n) if n >= 1 => Ok(Some(n)),
            _ => Err(errors::bad_positive_int(flag, v)),
        },
        _ => Ok(None),
    }
}

/// Parse an integer the way Haskell's `readMaybe :: String -> Maybe Int` does, to
/// match the reference's accept/reject boundary (see `workspace/BEHAVIOR.md` §11):
/// trims surrounding whitespace, allows a leading `-` with optional whitespace
/// before the digits, accepts decimal / `0x`hex / `0o`octal, and rejects `+`, a
/// decimal point, underscores, trailing non-whitespace, and the empty string.
/// Values beyond the 64-bit range wrap rather than fail, mirroring `fromInteger`.
pub fn read_haskell_int(s: &str) -> Option<i64> {
    let t = s.trim();
    if t.is_empty() {
        return None;
    }
    let (negative, mag) = match t.strip_prefix('-') {
        Some(rest) => (true, rest.trim_start()),
        None => (false, t),
    };
    if mag.is_empty() {
        return None;
    }
    let (digits, radix) = if let Some(h) = mag.strip_prefix("0x").or_else(|| mag.strip_prefix("0X"))
    {
        (h, 16u32)
    } else if let Some(oc) = mag.strip_prefix("0o").or_else(|| mag.strip_prefix("0O")) {
        (oc, 8u32)
    } else {
        (mag, 10u32)
    };
    if digits.is_empty() {
        return None;
    }
    // Accumulate with wrapping so out-of-range inputs mirror Haskell's wrap rather
    // than being rejected.
    let mut acc: i64 = 0;
    for ch in digits.chars() {
        let d = ch.to_digit(radix)?;
        acc = acc.wrapping_mul(radix as i64).wrapping_add(d as i64);
    }
    Some(if negative { acc.wrapping_neg() } else { acc })
}

//! Stream-aware output framing around opaque theory payloads.
//!
//! A batch run writes to two independent streams (see `workspace/BEHAVIOR.md`
//! §10). This module models which text lands on which stream and assembles both
//! byte-exactly. The theory pretty-print (`theory <name> … end`, including any
//! `WARNING:` block and the `Generated from:` comment) is an opaque payload slot;
//! everything around it — the maude preamble, the per-theory progress markers, and
//! the "summary of summaries" block — is built here.
//!
//! Stream assignment: the maude preamble and progress markers go to stderr;
//! payloads and the summary block go to stdout.

use crate::stream::Streams;
use crate::version::{maude_preamble, MaudeInfo};

/// Width of the `=` rule that brackets the summary block (observed: 78).
const RULE_WIDTH: usize = 78;

/// Per-theory progress phases, in the order printed for a fully closed theory.
#[derive(Debug, Clone, Copy)]
pub enum Phase {
    Loaded,
    Translated,
    DerivationChecksStarted,
    DerivationChecksEnded,
    Closed,
}

impl Phase {
    fn text(self) -> &'static str {
        match self {
            Phase::Loaded => "Theory loaded",
            Phase::Translated => "Theory translated",
            Phase::DerivationChecksStarted => "Derivation checks started",
            Phase::DerivationChecksEnded => "Derivation checks ended",
            Phase::Closed => "Theory closed",
        }
    }
}

/// The five progress phases a closed theory reports.
pub const CLOSED_PHASES: [Phase; 5] = [
    Phase::Loaded,
    Phase::Translated,
    Phase::DerivationChecksStarted,
    Phase::DerivationChecksEnded,
    Phase::Closed,
];

/// One progress line: `[Theory <name>] <phase>\n` (stderr).
pub fn progress_line(theory: &str, phase: Phase) -> String {
    format!("[Theory {}] {}\n", theory, phase.text())
}

fn progress_block(theory: &str, phases: &[Phase]) -> String {
    phases.iter().map(|p| progress_line(theory, *p)).collect()
}

/// Whether a lemma quantifies over all traces or asserts an existing trace.
#[derive(Debug, Clone, Copy)]
pub enum TraceKind {
    AllTraces,
    ExistsTrace,
}

impl TraceKind {
    fn text(self) -> &'static str {
        match self {
            TraceKind::AllTraces => "all-traces",
            TraceKind::ExistsTrace => "exists-trace",
        }
    }
}

/// Per-lemma verdict.
#[derive(Debug, Clone, Copy)]
pub enum LemmaResult {
    Verified,
    Falsified,
    AnalysisIncomplete,
}

impl LemmaResult {
    fn text(self) -> &'static str {
        match self {
            LemmaResult::Verified => "verified",
            LemmaResult::Falsified => "falsified",
            LemmaResult::AnalysisIncomplete => "analysis incomplete",
        }
    }
}

/// One line of a theory's summary body.
#[derive(Debug, Clone)]
pub enum SummaryEntry {
    Lemma { name: String, kind: TraceKind, result: LemmaResult, steps: u64 },
    /// `WARNING: <count> wellformedness check failed!` (note the singular "check").
    Warning { count: u64 },
}

impl SummaryEntry {
    fn text(&self) -> String {
        match self {
            SummaryEntry::Lemma { name, kind, result, steps } => {
                format!("{} ({}): {} ({} steps)", name, kind.text(), result.text(), steps)
            }
            SummaryEntry::Warning { count } => {
                format!("WARNING: {} wellformedness check failed!", count)
            }
        }
    }
}

/// One theory's contribution to the "summary of summaries" block.
#[derive(Debug, Clone)]
pub struct Summary {
    /// The `analyzed:` path, echoed exactly as given on the command line.
    pub analyzed: String,
    /// The `output:` path, present only when the theory was written to a file
    /// (`-o`/`-O`).
    pub output: Option<String>,
    /// Rendered as seconds with two decimals (e.g. `0.39s`).
    pub processing_time: f64,
    pub entries: Vec<SummaryEntry>,
}

impl Summary {
    /// The theory's block: the `analyzed:` header, a blank line, the aligned
    /// key/value rows (`output:` when present, then `processing time:`), the
    /// two-space separator line, then one line per entry.
    fn render_block(&self) -> String {
        let mut b = String::new();
        b.push_str(&format!("analyzed: {}\n", self.analyzed));
        b.push('\n');

        // Aligned key/value rows: labels right-padded to the widest label, then a
        // single space, so every value starts at the same column.
        let mut rows: Vec<(&str, String)> = Vec::new();
        if let Some(o) = &self.output {
            rows.push(("output:", o.clone()));
        }
        rows.push(("processing time:", format!("{:.2}s", self.processing_time)));
        let width = rows.iter().map(|(label, _)| label.len()).max().unwrap_or(0);
        for (label, value) in &rows {
            b.push_str("  ");
            b.push_str(label);
            for _ in 0..(width - label.len()) {
                b.push(' ');
            }
            b.push(' ');
            b.push_str(value);
            b.push('\n');
        }

        b.push_str("  \n"); // literal two-space separator line
        for e in &self.entries {
            b.push_str(&format!("  {}\n", e.text()));
        }
        b
    }
}

/// The full "summary of summaries" section as it appears on stdout: a leading
/// blank line (the payload/summary separator, always present), the top `=` rule,
/// the header, each theory block preceded by a blank line, a trailing blank line,
/// and the bottom rule.
pub fn render_summary(summaries: &[Summary]) -> String {
    let rule = "=".repeat(RULE_WIDTH);
    let mut out = String::new();
    out.push('\n');
    out.push_str(&rule);
    out.push('\n');
    out.push_str("summary of summaries:\n");
    for s in summaries {
        out.push('\n');
        out.push_str(&s.render_block());
    }
    out.push('\n');
    out.push_str(&rule);
    out.push('\n');
    out
}

/// A theory processed by a closed batch run.
#[derive(Debug, Clone)]
pub struct BatchTheory {
    /// Name used in the `[Theory <name>]` progress markers (stderr).
    pub name: String,
    /// The printed theory payload (stdout), or `None` when it was written to an
    /// output file instead.
    pub payload: Option<String>,
    /// This theory's summary contribution (stdout).
    pub summary: Summary,
}

/// A closed batch run over one or more theories.
///
/// stderr: the maude preamble, then each theory's five progress markers in order.
/// stdout: the printed payloads (in order), then one combined summary block.
pub fn frame_batch(maude: &MaudeInfo, theories: &[BatchTheory]) -> Streams {
    let mut s = Streams::default();
    s.err.push_str(&maude_preamble(maude));
    for t in theories {
        s.err.push_str(&progress_block(&t.name, &CLOSED_PHASES));
    }
    for t in theories {
        if let Some(p) = &t.payload {
            s.out.push_str(p);
        }
    }
    let summaries: Vec<Summary> = theories.iter().map(|t| t.summary.clone()).collect();
    s.out.push_str(&render_summary(&summaries));
    s
}

/// A theory under `--parse-only`: its name (for the single progress marker) and
/// its opaque payload.
#[derive(Debug, Clone)]
pub struct LoadedTheory {
    pub name: String,
    pub payload: String,
}

/// A `--parse-only` run: stderr carries one `Theory loaded` marker per theory (no
/// preamble); stdout carries the concatenated payloads (no summary block).
pub fn frame_parse_only(theories: &[LoadedTheory]) -> Streams {
    let mut s = Streams::default();
    for t in theories {
        s.err.push_str(&progress_line(&t.name, Phase::Loaded));
        s.out.push_str(&t.payload);
    }
    s
}

/// A `variants` run: stdout carries the variant payload; stderr carries only the
/// maude preamble (no progress markers, no summary).
pub fn frame_variants(maude: &MaudeInfo, payload: &str) -> Streams {
    Streams { out: payload.to_string(), err: maude_preamble(maude) }
}

//! Clean-room reimplementation of the tamarin-prover CLI/console text surface.
//!
//! Unit D of the relicensing effort. Every observable string in this crate was
//! derived from black-box probing of the compiled binary (see
//! `workspace/BEHAVIOR.md` and `workspace/QUERIES.log`); exact output strings
//! (help pages, banners, error texts) are stored as observed-output fixtures and
//! treated as opaque compatibility content. The parsing architecture, flag-table
//! model, and framing assembly are original.
//!
//! Public surface:
//! - [`parse`] : `parse(argv) -> Result<Command, ParseError>` — the structural
//!   command (mode, positionals, raw flag occurrences), or ready-to-print error.
//! - [`parse_args`] : `parse_args(argv) -> Result<Parsed, ParseError>` — a typed,
//!   value-validated command line ([`Args`]) with defaults applied.
//! - [`render_help`] / [`render_version`] : the help pages and version banner.
//! - [`framing`] : the stream-aware batch frame around opaque theory payloads.
//! - [`errors`] : renderers for the runtime error lines emitted after parsing.
//! - [`stream`] : the two-stream output model ([`Stream`], [`Streams`]).

pub mod args;
pub mod errors;
pub mod framing;
pub mod help;
pub mod modes;
pub mod parse;
pub mod stream;
pub mod version;

pub use args::{parse_args, Args, OutputModule, Parsed, PartialEval, StopOnTrace};
pub use errors::{CliError, ParseError};
pub use help::render_help;
pub use modes::Mode;
pub use parse::{parse, Command, Options, RunSpec};
pub use stream::{Stream, Streams};
pub use version::{render_version, VersionInfo};

//! Thin driver exercising the CLI text surface.
//!
//! Handles the pure-text paths (help, version, parse/validation errors)
//! byte-for-byte so they can be verified against the black-box binary. `Run` has
//! no prover engine behind it here — real integration wires the typed
//! [`cli_clean::Args`] into the prover and uses [`cli_clean::framing`] to wrap its
//! output across the two streams.

use std::process::exit;

use cli_clean::stream::Stream;
use cli_clean::version::{MaudeInfo, VersionInfo};
use cli_clean::{parse_args, render_version, Parsed};

/// Version slots as observed from the reference build. Real integration injects
/// the actual build metadata of the hosting binary.
fn observed_version_info() -> VersionInfo {
    VersionInfo {
        maude: MaudeInfo::default(),
        tamarin_version: "1.13.0".to_string(),
        copyright_years: "2010-2023".to_string(),
        git_description: "0234f6a1abee25677c0accef62de0ac2883b0347 (with uncommited changes), branch: HEAD"
            .to_string(),
        compiled_at: "2026-07-16 18:33:16.036427196 UTC".to_string(),
    }
}

fn main() {
    let argv: Vec<String> = std::env::args().skip(1).collect();
    match parse_args(&argv) {
        Ok(Parsed::Help(mode)) => {
            print!("{}", cli_clean::render_help(mode));
            exit(0);
        }
        Ok(Parsed::Version) => {
            print!("{}", render_version(&observed_version_info()));
            exit(0);
        }
        Ok(Parsed::Run(args)) => {
            // Text-surface stub: no prover engine in this crate.
            eprintln!(
                "[cli-clean] parsed: mode={:?} positional={:?} bound={:?} stop_on_trace={:?} output_module={:?} processors={:?}",
                args.mode,
                args.positional,
                args.bound,
                args.stop_on_trace,
                args.output_module,
                args.processors,
            );
            exit(0);
        }
        Err(e) => {
            match e.stream {
                Stream::Out => print!("{}", e.text),
                Stream::Err => eprint!("{}", e.text),
            }
            exit(e.exit_code);
        }
    }
}

